   CREATE FUNCTION get_following_feed(p_user_id UUID, p_limit INT, p_before TIMESTAMPTZ)
   RETURNS TABLE (...) AS $$
   -- PostgreSQL-native pagination logic
   -- Avoids sending 100k IDs in REST API
   $$;
   ```

