```javascript
const MILESTONES = [7, 14, 30, 50, 100];

const getNextMilestone = (count) => MILESTONES.find(m => m > count) || null;

export const getOverallEncouragement = (personal, streakCount, freezeAvailable = false) => {
    const posts = personal?.posts_written || 0;
    const nextMilestone = getNextMilestone(streakCount);
    const daysToNext = nextMilestone ? nextMilestone - streakCount : null;

    // Milestone proximity creates urgency (highest priority)
    if (daysToNext === 1) return `One more day and you hit ${nextMilestone}. Don't stop now.`;
    if (daysToNext === 2) return `Two days from ${nextMilestone}. The finish line is right there.`;
    if (daysToNext === 3) return `${streakCount} days in. Only 3 more to ${nextMilestone}.`;

    // Celebrate recent milestone (user just crossed one)
    if (streakCount === 100) return 'Triple digits. You are the streak.';
    if (streakCount === 50) return 'Fifty days of showing up. That is rare.';
    if (streakCount === 30) return 'A full month. Your habit is locked in.';
    if (streakCount === 14) return 'Two weeks of writing. Momentum is real.';
    if (streakCount === 7) return 'One week down. The hardest part is over.';

    // Freeze awareness (creates tension about the safety net)
    if (freezeAvailable && streakCount >= 7) return `${streakCount} days strong, with a safety net ready. Keep going.`;

    // General streak encouragement
    if (streakCount >= 50) return 'Consistency is your superpower. The words know where to find you.';
    if (streakCount >= 14) return "Don't break the streak. Your consistency is paying off.";
    if (streakCount >= 7) return 'The rhythm is building. Your readers can feel it.';
    if (streakCount >= 3) return `Day ${streakCount}. Keep the chain going.`;
    if (streakCount >= 1) return 'You showed up. That matters more than you think.';

    // Fallback to post-based
    if (posts >= 7) return 'Prolific week. Your readers can feel the momentum.';
    if (posts >= 3) return 'Solid pace this week. Keep the words flowing.';
    if (posts === 1) return 'You showed up. That matters more than you think.';
    if (posts === 0) return 'A quiet week. Sometimes the best ideas need silence first.';
    return 'Your weekly writing at a glance.';
};
```

